import{_ as t,o as r,c as e,ag as p}from"./chunks/framework.ETe_P6d1.js";const s="/kaiping-reports/assets/1.Bl37sFlp.jpg",o="/kaiping-reports/assets/2.CcYp0P-u.jpg",i="/kaiping-reports/assets/3.BnfbCOu5.jpg",n="/kaiping-reports/assets/4.29XUYiq-.jpg",_="/kaiping-reports/assets/5.DkzJ6bPv.jpg",l="/kaiping-reports/assets/6.jjUFjTqf.jpg",h="/kaiping-reports/assets/7.zh62Ce1Z.jpg",c="/kaiping-reports/assets/8.DiX96GPB.jpg",d="/kaiping-reports/assets/9.CzPfNvF_.jpg",m="/kaiping-reports/assets/10.D0AlXPoj.jpg",g="/kaiping-reports/assets/11.Do_qKK3h.jpg",D=JSON.parse('{"title":"一栏融中西——开平侨乡建筑阳台栏杆的中西融合设计研究调研报告","description":"","frontmatter":{},"headers":[],"relativePath":"reports/王梓瑞/王梓瑞_关于开平侨乡阳台栏杆的调研报告2.md","filePath":"reports/王梓瑞/王梓瑞_关于开平侨乡阳台栏杆的调研报告2.md"}'),u={name:"reports/王梓瑞/王梓瑞_关于开平侨乡阳台栏杆的调研报告2.md"};function q(b,a,k,f,P,x){return r(),e("div",null,[...a[0]||(a[0]=[p('<h1 id="一栏融中西——开平侨乡建筑阳台栏杆的中西融合设计研究调研报告" tabindex="-1">一栏融中西——开平侨乡建筑阳台栏杆的中西融合设计研究调研报告 <a class="header-anchor" href="#一栏融中西——开平侨乡建筑阳台栏杆的中西融合设计研究调研报告" aria-label="Permalink to &quot;一栏融中西——开平侨乡建筑阳台栏杆的中西融合设计研究调研报告&quot;">​</a></h1><p><strong>作者：王梓瑞</strong></p><h2 id="一、调研信息" tabindex="-1">一、调研信息 <a class="header-anchor" href="#一、调研信息" aria-label="Permalink to &quot;一、调研信息&quot;">​</a></h2><p>考察地点：广东省江门市开平市 考察时间：2026年4月1日 考察小组：王梓瑞、胡月好 指导教师：石拓</p><h2 id="二、调研背景与目的" tabindex="-1">二、调研背景与目的 <a class="header-anchor" href="#二、调研背景与目的" aria-label="Permalink to &quot;二、调研背景与目的&quot;">​</a></h2><p>开平市是全国著名侨乡，自十六世纪中叶起，世界风云变换，开平的居民经历着土地兼并、苛捐杂税与战乱频频的困境，生存艰难，于是大批民众开始冒着生命危险向外迁徙，在海外谋生。数年后，华侨心系故土，秉持落叶归根、饮水思源的家国情怀，热心支援革命、捐资兴学、修桥铺路、建设家乡。也正是这段漂洋过海、谋生思乡的历程，孕育了开平独有的中西合璧建筑——它们并非设计师凭空创造，而是华侨将海外见闻与生活智慧带回故乡、把世界带回家、从世界落回家的真实历史见证。</p><p>阳台是民居的复合功能区，其承载着建筑立面美化、连接室内外、瞭望防御、晾晒休憩与邻里沟通交往等功能，且本身具有丰富的中西交流历史内涵，是多维度研究开平侨乡文化的重要空间节点。而阳台栏杆作为阳台空间的核心围护构件与视觉焦点，更是将阳台的功能价值、美学价值与文化价值推向极致的关键载体，是解读开平近代侨乡建筑营造智慧、侨乡社会生活与中西文化互动的重要研究单元。</p><h2 id="三、阳台的历史" tabindex="-1">三、阳台的历史 <a class="header-anchor" href="#三、阳台的历史" aria-label="Permalink to &quot;三、阳台的历史&quot;">​</a></h2><p>“阳台”一词在中国有着悠久的历史，最早出现在春秋战国时楚人宋玉的《高唐赋序》：“旦为朝云，暮为行雨，朝朝暮暮，阳台之下。”这里的阳台指代的是巫山之上的高台，从这以后，“阳台”在中国文艺作品中的概念就基本围绕着“理想之地”“男女合欢之所”与“美好之处”等含义，与现代所说的阳台有所差异。</p><p>中国早期虽无“阳台”这一建筑名称，但其功能与形态可追溯至战国时期。战国以来，统治者为彰显权力与满足宗教崇拜，修筑大量高台，伴随着高台建筑高度越来越高，部分高台周边修筑了木架构的围栏，防止人跌落，这种早期的围栏机构可视为阳台栏杆的雏形。东汉时期，木构塔楼的出现以及城市结构变化对夯土台造成冲击，夯土高台衰败，高层的木构塔楼中出现的“平坐”结构。平坐结构指：高台或楼层用斗拱、枋、铺板等挑出，更是展现了阳台作为“休闲远眺”空间的功能特征。</p><p>西方阳台雏形最早出现于古波斯与古希腊，以悬挑平台满足遮阳、通风与观景需求；古罗马将其发展为公共观演与身份展示的空间。至意大利文艺复兴时期，阳台形制成熟，宝瓶柱栏杆因形似石榴花被命名并广泛使用，成为西方古典建筑的标志性元素。19世纪中国被西方殖民者侵略，建筑风格受到西方建筑文化影响，阳台结构出现在中国的建筑中。鲁迅的《且介亭杂文末编·“立此存照”（二）》写到：“从杏珍之箱箧中发现他人寄与之情书一封，原文云：‘……早晨等在洋台上，看你开门，我多看见你芳影，很是快活。’”此处的“洋台”即为“阳台”。</p><h2 id="四、阳台栏杆类型与形式特征" tabindex="-1">四、阳台栏杆类型与形式特征 <a class="header-anchor" href="#四、阳台栏杆类型与形式特征" aria-label="Permalink to &quot;四、阳台栏杆类型与形式特征&quot;">​</a></h2><p>开平近代建筑阳台栏杆在侨乡背景下，形成了多元形式特征，既立足岭南地域的实用需求，又深度融合中西建筑装饰语言，呈现出鲜明的侨乡专属风貌。</p><h3 id="_4-1-宝瓶柱栏杆" tabindex="-1">4.1 宝瓶柱栏杆 <a class="header-anchor" href="#_4-1-宝瓶柱栏杆" aria-label="Permalink to &quot;4.1 宝瓶柱栏杆&quot;">​</a></h3><p>宝瓶柱栏杆是以瓶形立柱为核心的阳台围护构件，原型源自西方文艺复兴时期的Baluster栏杆，后随华侨传入开平。经本土化改造后，它以陶瓷、混凝土为主要材料，既保留了西方栏杆的韵律感，又融入了中式“平安”的吉祥寓意，是开平侨乡建筑中西合璧的典型装饰符号。</p><p><img src="'+s+'" alt="图1：自力村碉楼宝瓶柱栏杆"><img src="'+o+'" alt="图2：仓东村稳怀楼宝瓶柱栏杆"></p><p>该栏杆为宝瓶式栏杆，但这一栏杆并非对西方样式的简单照搬，而是融合了开平地域特征与侨民需求的本土化改造成果：采用岭南地区常见的釉陶工艺，替代西方传统石材构件，更适配岭南潮湿多雨的气候，兼具耐候性与地域工艺特色，使西方装饰形式承载了本土祈福纳祥的文化内涵。</p><p><img src="'+i+'" alt="图3：佛罗伦萨劳伦齐阿纳图书馆门厅栏杆"></p><h3 id="_4-2-镂空造型栏杆" tabindex="-1">4.2 镂空造型栏杆 <a class="header-anchor" href="#_4-2-镂空造型栏杆" aria-label="Permalink to &quot;4.2 镂空造型栏杆&quot;">​</a></h3><p><img src="'+n+'" alt="图4：东堤旅店旧址"><img src="'+_+'" alt="图5：赤坎影院旧址"></p><p>如图，赤坎古镇分布大量镂空造型栏杆，形似岭南传统花型栏，但花纹更加丰富多样。其几何装饰语言融合中式传统古钱纹与卷草纹，同时采用了源自20世纪初西式流行的装饰艺术（Art Deco）风格表达。此类栏杆纹样结合中西方特色，镂空形制符合岭南潮湿闷热的地域实用需求。</p><h3 id="_4-3-雕花栏板" tabindex="-1">4.3 雕花栏板 <a class="header-anchor" href="#_4-3-雕花栏板" aria-label="Permalink to &quot;4.3 雕花栏板&quot;">​</a></h3><p><img src="'+l+'" alt="图6：立园文泮楼阳台栏板"><img src="'+h+'" alt="图7：立园晚香亭栏板"></p><p>作为立园的核心建筑之一，文泮楼的设计体现了园主谢维立对中西建筑文化的融合巧思。其阳台栏杆采用实心混凝土栏板形式，栏板上的连续等腰三角形浮雕，体现了西方Art Deco风格，以简洁对称的几何构图营造出秩序感与现代感，是当时西方建筑审美潮流在侨乡的直接体现。</p><p>图为开平立园晚香亭上层栏板的灰塑装饰，是侨乡建筑中中式传统吉祥纹样与岭南灰塑工艺结合的典型实例。</p><p>栏板的核心纹样为方胜纹，呈现出两个菱形压角相叠、互相扣合的典型特征，菱形四角的圆点装饰，是传统木雕工艺手法在灰塑上的复刻表达；中心方胜纹两侧搭配对称的缠枝花卉纹，寓意富贵绵延、生生不息。</p><p>方胜纹是中国传统“八宝纹”之一，源自古代祥瑞饰物，因两菱形紧密相扣，象征永结同心、同心同德，承载着侨民对家庭和睦、福气连绵的祈愿。在立园这座中西合璧的亭式建筑上，这一传统中式纹样以岭南水泥灰塑工艺呈现，与建筑的西式圆柱、弧形立面形成对比呼应。</p><p>文泮楼和晚香亭的雕花栏板体现了立园“外洋内中”的造园理念，也展现了开平侨乡建筑将本土文化内核与西式建筑形式巧妙融合的营造智慧。</p><h3 id="_4-4-组合栏杆" tabindex="-1">4.4 组合栏杆 <a class="header-anchor" href="#_4-4-组合栏杆" aria-label="Permalink to &quot;4.4 组合栏杆&quot;">​</a></h3><p><img src="'+c+'" alt="图8：赤坎古镇位元堂"><img src="'+d+'" alt="图9：路易十六时期小桌案"><img src="'+m+'" alt="图10：仓东村侯成谢公祠"></p><p>如图，此栏杆分为两部分，上方是简化的西式铁艺栏杆，下方是雕花栏板，花纹为欧洲传统茛苕纹，风格近似巴洛克、洛可可时期繁复的茛苕纹变体。呈现出欧洲巴洛克、洛可可时期茛苕纹的典型形态，线条流畅繁复，带有古典装饰的华丽感。栏板下方的立面还搭配了圆形浮雕与卷草纹样装饰，与天花与山花的雕花元素形成呼应，进一步强化了立面的装饰性。</p><p>茛苕纹是西方古典装饰中延续性极强的纹样母题，源自古希腊、古罗马时期的建筑柱饰，以茛苕植物叶片为原型，经程式化处理后成为象征生命力与秩序感的装饰符号，在欧洲建筑与器物装饰中沿用千年。图中路易十六时期的小桌案装饰，便清晰呈现了茛苕纹在欧洲近代器物中的应用形态，与赤坎位元堂栏杆上的纹样形成了直接的源流呼应。</p><p>不同于赤坎位元堂“上下分层”的组合栏杆，仓东村侯成谢公祠栏板采用同一平面上左右分区的形式，将西式灰塑浮雕与中式民俗彩画并置呈现，形成了鲜明的文化对话。</p><p>栏板左侧为西式灰塑浮雕装饰，其纹样形似西方巴洛克时期的涡卷徽章饰（Cartouche）。浮雕以对称的茛苕卷草纹为母题，两侧舒展卷曲的叶片是西方古典装饰中延续千年的茛苕纹典型形态，中心以柔和的“心形”替代了传统纹章的盾形元素。这种以混凝土/石灰为材料的灰塑工艺，既复刻了西式石雕的立体效果，又能抵御岭南潮湿多雨的气候侵蚀，是侨乡工匠结合地域条件的实用化改造。</p><p>栏板右侧为开平民俗题材彩画，是岭南祠堂建筑的典型装饰手法。画面以传统民俗场景或戏曲人物为核心，通过色彩与叙事性构图传递本土文化内涵，承载着族群教化与文化传承的功能，符合公祠文化功能，也是侨民对本土文化根脉的坚守。</p><p>这种同一栏板上中西元素并置的设计，打破了传统祠堂装饰的单一性，也弱化了西式元素的外来感，是开平侨乡工匠的创造性表达。它既彰显了归侨接触西方文明后的新视野，也保留了祠堂建筑对宗族文化与本土民俗的传承，直观体现了侨民“不忘本源、兼收并蓄”的文化心态，也让侯成谢公祠成为解读侨乡祠宅建筑融合特征的重要实例。</p><h3 id="_4-5-开平传统栏板" tabindex="-1">4.5 开平传统栏板 <a class="header-anchor" href="#_4-5-开平传统栏板" aria-label="Permalink to &quot;4.5 开平传统栏板&quot;">​</a></h3><p><img src="'+g+'" alt="图11：自力村铭石楼"></p><p>铭石楼栏板采用广府地区典型的彩灰塑工艺，该工艺既凭借灰塑基底的耐候性抵御岭南潮湿多雨的气候侵蚀，又通过彩绘弱化了传统高浮雕灰塑的厚重质感，使装饰效果轻盈华丽，与建筑立面的西式拱券柱廊、巴洛克式山花等外来形制形成风格协调，是广府传统工艺在侨乡建筑语境下的适应性改造。</p><p>栏板装饰以中国传统“主纹—辅纹”的构图逻辑展开：核心栏板为对称式双凤纹，凤凰羽毛舒展灵动，搭配卷草线条，延续了传统建筑中凤凰“祥瑞绵延、富贵吉祥”的文化寓意；两侧栏板则采用“蝠钱纹”组合，蝙蝠谐音“福”、铜钱象征财富，二者结合形成“福在眼前、财源广进”的祈愿符号，是侨乡建筑中极具代表性的吉祥纹样，承载了华侨对家业兴旺与生活顺遂的精神诉求；纹样间点缀的花叶装饰，既强化了构图的韵律感，也呼应了凤凰纹的自然意象，使整体装饰层次清晰、主题鲜明。</p><p>作为开平碉楼的典型代表，铭石楼的这组栏板装饰，是侨乡建筑中西结合文化特征的表现，既体现了华侨在海外接触西方文明后，对近代建筑语言的吸收与应用，也保留了对本土文化根脉的坚守，直观反映了开平侨乡“兼收并蓄、不忘本源”的文化心态，为解读侨乡建筑的多元融合特征提供了典型样本。</p><h2 id="五、结论" tabindex="-1">五、结论 <a class="header-anchor" href="#五、结论" aria-label="Permalink to &quot;五、结论&quot;">​</a></h2><p>本次调研以开平侨乡建筑阳台栏杆为核心对象，系统梳理了宝瓶柱栏杆、镂空造型栏杆、雕花栏板、组合栏杆及传统彩灰塑栏板五大类型的形式特征与设计逻辑。研究表明，开平侨乡阳台栏杆并非对西方建筑元素的简单复刻，而是结合岭南潮湿多雨的地域气候、本土营造工艺与华侨文化诉求完成的本土化创新。</p><p>其设计以西式形制为表、中式文化为里，将西方文艺复兴宝瓶柱、巴洛克茛苕纹、Art Deco几何纹样等装饰语言，与中式吉祥纹样、广府灰塑工艺、民俗彩画深度融合，既满足通风、防护等实用功能，又承载着华侨对家国故土的眷恋与对美好生活的祈愿。</p><p>开平侨乡阳台栏杆更是侨民“落叶归根、不忘本源”家国情怀的物化载体。近代侨民远赴海外打拼，将西方建筑形制与审美见闻带回故土，却在阳台栏杆的细节中始终锚定本土文化根脉：以蝠钱纹、双凤纹、方胜纹等中式吉祥符号，传递对家业兴旺、家庭和睦的祈愿；沿用广府传统灰塑工艺复刻装饰细节，延续故土营造技艺的基因。这种“外洋内中”的设计，并非对异域文化的全盘接纳，而是侨民在接触西方文明后，依然坚守本土文化认同的生动体现——他们以洋楼为载体，在故乡土地上建造融合海外经验与故土情怀的家园，让栏杆这一建筑细部，成为侨民“出洋立业、归乡安身”文化轨迹的缩影，也印证了侨乡建筑“兼容并蓄、不忘根本”的文化内核，为侨乡建筑遗产的保护、传承与当代设计应用提供了重要的实证依据。</p><h2 id="六、摄影记录" tabindex="-1">六、摄影记录 <a class="header-anchor" href="#六、摄影记录" aria-label="Permalink to &quot;六、摄影记录&quot;">​</a></h2><p>本报告共插入9张现场照片，分别展示： 图1 自力村碉楼宝瓶柱栏杆 图2 仓东村稳怀楼宝瓶柱栏杆 图4 东堤旅店旧址 图5 赤坎影院旧址 图6 立园文泮楼阳台栏板 图7 立园 晚香亭栏板 图8 赤坎古镇位元堂 图10 仓东村侯成谢公祠 图11 自力村铭石楼 其他图片来源网络</p><h2 id="七、参考文献" tabindex="-1">七、参考文献 <a class="header-anchor" href="#七、参考文献" aria-label="Permalink to &quot;七、参考文献&quot;">​</a></h2><p>[1]曹文心.公元3世纪之前中国高台建筑发展演变研究[D].西北大学,2019. [2]来源：《中国建筑史》作者：梁思成 [3]何璐西.佛山岭南建筑装饰纹样的特征与范式[J].时尚设计与工程,2025,(06):34-37. [4]黄利平.广府砖雕、灰塑与能工巧匠[J].寻根,2026,(01):131-136.</p>',49)])])}const A=t(u,[["render",q]]);export{D as __pageData,A as default};
